// ---- Performance and Memory Basics ----

// ---- Memory leaks ----
class LeakyActivity : AppCompatActivity() {
    // 1. Static reference leak
    companion object {
        var leakyReference: Any? = null
    }

    // 2. Inner class leak
    inner class LeakyClass {
        // Holds reference to outer Activity
    }

    // 3. Anonymous class leak
    fun leakyMethod() {
        Thread {
            // Holds reference to Activity
            Thread.sleep(10000)
        }.start()
    }

    // 4. Handler leak
    private val handler = Handler(Looper.getMainLooper())

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        // Leak 1: Static reference
        leakyReference = this

        // Leak 2: Inner class
        val leaky = LeakyClass()

        // Leak 3: Handler
        handler.postDelayed({
            // This holds reference to Activity
        }, 10000)
    }
}

// ---- Memory leak fixes ----
class FixedActivity : AppCompatActivity() {
    // Use WeakReference
    private var leakyReference: WeakReference<FixedActivity>? = null

    // Use static inner class (no outer reference)
    class SafeClass

    // Use weak references for handlers
    private val handler = Handler(Looper.getMainLooper())
    private var runnable: Runnable? = null

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        leakyReference = WeakReference(this)

        // Safe Runnable
        runnable = Runnable {
            // Use weak reference
            leakyReference?.get()?.let { activity ->
                // Safe to use
            }
        }
        handler.postDelayed(runnable!!, 10000)
    }

    override fun onDestroy() {
        super.onDestroy()
        handler.removeCallbacks(runnable!!)
    }
}

// ---- Performance optimization ----
class PerformanceOptimizer {
    // ---- Lazy initialization ----
    private val heavyObject: HeavyObject by lazy {
        HeavyObject() // Only created when used
    }

    // ---- Reusing objects ----
    private val stringBuilder = StringBuilder()
    fun buildString(): String {
        stringBuilder.clear()
        stringBuilder.append("Hello")
        stringBuilder.append("World")
        return stringBuilder.toString()
    }

    // ---- Avoiding allocations in loops ----
    fun processItems(items: List<String>): List<String> {
        val result = mutableListOf<String>()
        for (item in items) {
            // Reuse StringBuilder
            val sb = StringBuilder()
            sb.append(item)
            result.add(sb.toString())
        }
        return result
    }

    // ---- Efficient list operations ----
    fun filterItems(items: List<String>): List<String> {
        return items.filter { it.length > 3 }
    }

    // ---- Use primitive types when possible ----
    fun sumNumbers(numbers: List<Int>): Int {
        var sum = 0 // Primitive, not Integer
        for (n in numbers) {
            sum += n
        }
        return sum
    }
}

// ---- ViewModel memory management ----
class MemoryViewModel : ViewModel() {
    // ViewModel survives configuration changes
    // But is cleared when Activity finishes

    private val _data = MutableStateFlow("")
    val data: StateFlow<String> = _data.asStateFlow()

    override fun onCleared() {
        super.onCleared()
        // Clean up resources
        // Cancel coroutines
        // Close connections
        println("ViewModel cleared")
    }
}

// ---- Leak detection ----
class LeakDetection {
    // Use LeakCanary for detection
    // Add to build.gradle:
    // debugImplementation("com.squareup.leakcanary:leakcanary-android:2.12")

    // Monitor memory usage
    fun getMemoryInfo(): String {
        val runtime = Runtime.getRuntime()
        val maxMemory = runtime.maxMemory() / (1024 * 1024)
        val totalMemory = runtime.totalMemory() / (1024 * 1024)
        val freeMemory = runtime.freeMemory() / (1024 * 1024)
        return "Memory: $totalMemory MB used, $freeMemory MB free, $maxMemory MB max"
    }
}

